1208	        if (u.err) {
1209	            ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1210	                               "%s in debug_connection \"%V\"",
1211	                               u.err, &u.host);
1212	        }
1213	
1214	        return NGX_CONF_ERROR;
1215	    }
1216	
