1231	            sin6 = (struct sockaddr_in6 *) u.addrs[i].sockaddr;
1232	            cidr[i].u.in6.addr = sin6->sin6_addr;
1233	            ngx_memset(cidr[i].u.in6.mask.s6_addr, 0xff, 16);
1234	            break;
1235	#endif
1236	
